create extension if not exists pgcrypto;
do $$ begin create type public.app_role as enum ('owner','manager','sales','installer','office'); exception when duplicate_object then null; end $$;
do $$ begin create type public.lead_status as enum ('new','attempted','no_answer','voicemail','text_sent','contacted','estimate_scheduled','quote_sent','follow_up_due','approved','lost','do_not_contact','no_response'); exception when duplicate_object then null; end $$;
do $$ begin create type public.time_entry_status as enum ('open','closed','approved'); exception when duplicate_object then null; end $$;
create table if not exists public.profiles(id uuid primary key references auth.users(id) on delete cascade,email text not null,full_name text not null default '',role public.app_role not null default 'installer',active boolean not null default true,created_at timestamptz not null default now());
create table if not exists public.leads(id uuid primary key default gen_random_uuid(),source text not null default 'Angi',first_name text not null default '',last_name text not null default '',phone text not null default '',email text not null default '',city text not null default '',service_address text not null default '',service_requested text not null default '',original_message text not null default '',status public.lead_status not null default 'new',attempt_count int not null default 0,assigned_to uuid references public.profiles(id),next_follow_up_at timestamptz,received_at timestamptz not null default now(),created_by uuid not null default auth.uid() references public.profiles(id),updated_at timestamptz not null default now());
create table if not exists public.lead_activities(id uuid primary key default gen_random_uuid(),lead_id uuid not null references public.leads(id) on delete cascade,activity_type text not null,notes text not null default '',completed_by uuid not null default auth.uid() references public.profiles(id),created_at timestamptz not null default now());
create table if not exists public.jobs(id uuid primary key default gen_random_uuid(),title text not null default '',service_address text not null default '',scheduled_start timestamptz,scheduled_end timestamptz,status text not null default 'Scheduled',notes text not null default '',assigned_to uuid references public.profiles(id),created_by uuid not null default auth.uid() references public.profiles(id),created_at timestamptz not null default now());
create table if not exists public.time_entries(id uuid primary key default gen_random_uuid(),employee_id uuid not null default auth.uid() references public.profiles(id) on delete cascade,job_id uuid references public.jobs(id),clock_in timestamptz not null default now(),clock_out timestamptz,status public.time_entry_status not null default 'open',employee_note text not null default '',approved_by uuid references public.profiles(id),approved_at timestamptz,created_at timestamptz not null default now());
create table if not exists public.time_breaks(id uuid primary key default gen_random_uuid(),time_entry_id uuid not null references public.time_entries(id) on delete cascade,break_start timestamptz not null default now(),break_end timestamptz,unpaid boolean not null default true,created_at timestamptz not null default now());
create table if not exists public.time_adjustments(id uuid primary key default gen_random_uuid(),time_entry_id uuid not null references public.time_entries(id) on delete cascade,old_clock_in timestamptz,old_clock_out timestamptz,new_clock_in timestamptz,new_clock_out timestamptz,reason text not null,adjusted_by uuid not null default auth.uid() references public.profiles(id),created_at timestamptz not null default now());
create or replace function public.is_owner() returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from public.profiles where id=auth.uid() and active and role in ('owner','manager'))$$;
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$begin insert into public.profiles(id,email,full_name,role) values(new.id,coalesce(new.email,''),coalesce(new.raw_user_meta_data->>'full_name',''),case when lower(coalesce(new.email,''))='dynamictintzllc@gmail.com' then 'owner'::public.app_role else 'installer'::public.app_role end) on conflict(id) do update set email=excluded.email; return new; end$$;
drop trigger if exists on_auth_user_created on auth.users; create trigger on_auth_user_created after insert or update of email on auth.users for each row execute procedure public.handle_new_user();
insert into public.profiles(id,email,full_name,role) select id,coalesce(email,''),coalesce(raw_user_meta_data->>'full_name',''),case when lower(coalesce(email,''))='dynamictintzllc@gmail.com' then 'owner'::public.app_role else 'installer'::public.app_role end from auth.users on conflict(id) do nothing;
update public.profiles set full_name='Jeremy McPherson',role='owner' where lower(email)='dynamictintzllc@gmail.com';
update public.profiles set full_name='Justin Thomas',role='installer' where lower(email)='jdogg2009@icloud.com';
alter table public.profiles enable row level security; alter table public.leads enable row level security; alter table public.lead_activities enable row level security; alter table public.jobs enable row level security; alter table public.time_entries enable row level security; alter table public.time_breaks enable row level security; alter table public.time_adjustments enable row level security;
drop policy if exists p_profiles_select on public.profiles; create policy p_profiles_select on public.profiles for select using(id=auth.uid() or public.is_owner());
drop policy if exists p_profiles_update on public.profiles; create policy p_profiles_update on public.profiles for update using(public.is_owner()) with check(public.is_owner());
drop policy if exists p_leads_select on public.leads; create policy p_leads_select on public.leads for select using(public.is_owner() or assigned_to=auth.uid() or created_by=auth.uid());
drop policy if exists p_leads_insert on public.leads; create policy p_leads_insert on public.leads for insert with check(auth.uid() is not null);
drop policy if exists p_leads_update on public.leads; create policy p_leads_update on public.leads for update using(public.is_owner() or assigned_to=auth.uid() or created_by=auth.uid()) with check(public.is_owner() or assigned_to=auth.uid() or created_by=auth.uid());
drop policy if exists p_leads_delete on public.leads; create policy p_leads_delete on public.leads for delete using(public.is_owner());
drop policy if exists p_act_select on public.lead_activities; create policy p_act_select on public.lead_activities for select using(public.is_owner() or exists(select 1 from public.leads l where l.id=lead_id and (l.assigned_to=auth.uid() or l.created_by=auth.uid())));
drop policy if exists p_act_insert on public.lead_activities; create policy p_act_insert on public.lead_activities for insert with check(auth.uid() is not null);
drop policy if exists p_jobs_select on public.jobs; create policy p_jobs_select on public.jobs for select using(public.is_owner() or assigned_to=auth.uid() or created_by=auth.uid());
drop policy if exists p_jobs_write on public.jobs; create policy p_jobs_write on public.jobs for all using(public.is_owner() or created_by=auth.uid()) with check(public.is_owner() or created_by=auth.uid());
drop policy if exists p_time_select on public.time_entries; create policy p_time_select on public.time_entries for select using(public.is_owner() or employee_id=auth.uid());
drop policy if exists p_time_insert on public.time_entries; create policy p_time_insert on public.time_entries for insert with check(employee_id=auth.uid());
drop policy if exists p_time_update on public.time_entries; create policy p_time_update on public.time_entries for update using(public.is_owner() or employee_id=auth.uid()) with check(public.is_owner() or employee_id=auth.uid());
drop policy if exists p_break_select on public.time_breaks; create policy p_break_select on public.time_breaks for select using(public.is_owner() or exists(select 1 from public.time_entries t where t.id=time_entry_id and t.employee_id=auth.uid()));
drop policy if exists p_break_write on public.time_breaks; create policy p_break_write on public.time_breaks for all using(public.is_owner() or exists(select 1 from public.time_entries t where t.id=time_entry_id and t.employee_id=auth.uid())) with check(public.is_owner() or exists(select 1 from public.time_entries t where t.id=time_entry_id and t.employee_id=auth.uid()));
drop policy if exists p_adj_owner on public.time_adjustments; create policy p_adj_owner on public.time_adjustments for all using(public.is_owner()) with check(public.is_owner());
create or replace view public.time_entry_totals with(security_invoker=true) as select t.*,greatest(0,extract(epoch from(coalesce(t.clock_out,now())-t.clock_in))/3600-coalesce((select sum(extract(epoch from(coalesce(b.break_end,now())-b.break_start))/3600) from public.time_breaks b where b.time_entry_id=t.id and b.unpaid),0)) net_hours from public.time_entries t;
